```tsx
import { Check } from 'lucide-react';
import { CommandItem } from '@/layers/shared/ui';
import { useAgentVisual } from '@/layers/entities/agent';
import { shortenHomePath } from '@/layers/shared/lib';
import type { AgentPath } from '@dorkos/shared/types';

interface AgentCommandItemProps {
  /** Agent data from useMeshAgentPaths */
  agent: AgentPath;
  /** Whether this is the currently active agent */
  isActive: boolean;
  /** Called when the user selects this agent */
  onSelect: (e: React.MouseEvent | React.KeyboardEvent) => void;
}

/**
 * Custom CommandItem rendering for agent rows in the global palette.
 *
 * Layout:
 * [colored dot] agent-name          ~/path/to/project    [checkmark if active]
 *               "Optional description"
 *
 * Supports Cmd+Click / Ctrl+Click to open in a new browser tab.
 */
export function AgentCommandItem({ agent, isActive, onSelect }: AgentCommandItemProps) {
  const visual = useAgentVisual(agent, agent.projectPath);

  return (
    <CommandItem
      value={agent.name}
      keywords={[agent.projectPath, agent.description ?? '', agent.id]}
      onSelect={() => {
        // cmdk's onSelect doesn't pass the native event, so we use a ref-based
        // approach or handle modifier detection in the parent. For simplicity,
        // call onSelect with a synthetic event — the parent handles the logic.
        onSelect({} as React.MouseEvent);
      }}
      className="flex items-start gap-2 py-2"
      forceMount={isActive ? true : undefined}
    >
      {/* Colored dot */}
      <span
        className="mt-1.5 size-2.5 flex-shrink-0 rounded-full"
        style={{ backgroundColor: visual.color }}
      />

      {/* Agent info */}
      <div className="min-w-0 flex-1">
        <div className="flex items-center gap-2">
          <span className="text-sm">{visual.emoji}</span>
          <span className="truncate text-sm font-semibold">{agent.name}</span>
          <span className="text-muted-foreground ml-auto flex-shrink-0 text-xs">
            {shortenHomePath(agent.projectPath)}
          </span>
          {isActive && <Check className="text-muted-foreground size-4 flex-shrink-0" />}
        </div>
        {agent.description && (
          <p className="text-muted-foreground truncate text-xs">{agent.description}</p>
        )}
      </div>
    </CommandItem>
  );
}
```

Note: The `AgentPath` type needs to include at minimum `{ id: string; name: string; projectPath: string; description?: string; }`. Verify this matches what `useMeshAgentPaths()` returns. If the type doesn't include color/emoji fields, `useAgentVisual` will use its fallback logic (hash-based color, default emoji).

