Create a hook that gathers data from multiple sources and organizes it into content groups for the command palette.

## New File: `apps/client/src/layers/features/command-palette/model/use-palette-items.ts`

This hook assembles all five content groups described in the spec:

1. **Recent Agents** — frecency-sorted, top 5, active agent pinned first
2. **All Agents** — full list from mesh, shown in search / `@` mode
3. **Features** — static list: Pulse, Relay, Mesh, Settings
4. **Commands** — from `useCommands()` entity hook
5. **Quick Actions** — static list: New Session, Discover Agents, Browse Filesystem, Toggle Theme

```typescript
import { useMemo } from 'react';
import { useMeshAgentPaths } from '@/layers/entities/mesh';
import { useCommands } from '@/layers/entities/command';
import { useAgentFrecency } from './use-agent-frecency';
import type { AgentPath } from '@dorkos/shared/types';

interface FeatureItem {
  id: string;
  label: string;
  icon: string; // Lucide icon name
  shortcut?: string;
  action: string; // Action identifier for the parent to dispatch
}

interface QuickActionItem {
  id: string;
  label: string;
  icon: string;
  action: string;
}

interface CommandItemData {
  name: string;
  description?: string;
}

interface PaletteItems {
  recentAgents: AgentPath[];
  allAgents: AgentPath[];
  features: FeatureItem[];
  commands: CommandItemData[];
  quickActions: QuickActionItem[];
  isLoading: boolean;
}

const FEATURES: FeatureItem[] = [
  { id: 'pulse', label: 'Pulse Scheduler', icon: 'Clock', action: 'openPulse' },
  { id: 'relay', label: 'Relay Messaging', icon: 'Radio', action: 'openRelay' },
  { id: 'mesh', label: 'Mesh Network', icon: 'Globe', action: 'openMesh' },
  { id: 'settings', label: 'Settings', icon: 'Settings', shortcut: undefined, action: 'openSettings' },
];

const QUICK_ACTIONS: QuickActionItem[] = [
  { id: 'new-session', label: 'New Session', icon: 'Plus', action: 'newSession' },
  { id: 'discover', label: 'Discover Agents', icon: 'Search', action: 'discoverAgents' },
  { id: 'browse', label: 'Browse Filesystem', icon: 'FolderOpen', action: 'browseFilesystem' },
  { id: 'theme', label: 'Toggle Theme', icon: 'Moon', action: 'toggleTheme' },
];

const MAX_RECENT_AGENTS = 5;

/**
 * Assemble all content groups for the command palette.
 *
 * @param activeCwd - Current working directory to identify the active agent
 */
export function usePaletteItems(activeCwd: string | null): PaletteItems {
  const { data: agentPaths, isLoading: agentsLoading } = useMeshAgentPaths();
  const { data: commandsData } = useCommands();
  const { getSortedAgentIds } = useAgentFrecency();

  const allAgents = useMemo(() => agentPaths ?? [], [agentPaths]);

  const recentAgents = useMemo(() => {
    if (allAgents.length === 0) return [];

    const agentMap = new Map(allAgents.map((a) => [a.id, a]));
    const sortedIds = getSortedAgentIds(allAgents.map((a) => a.id));

    // Pin active agent first
    const activeAgent = activeCwd
      ? allAgents.find((a) => a.projectPath === activeCwd)
      : null;

    const recent: AgentPath[] = [];
    if (activeAgent) recent.push(activeAgent);

    for (const id of sortedIds) {
      if (recent.length >= MAX_RECENT_AGENTS) break;
      const agent = agentMap.get(id);
      if (agent && agent.id !== activeAgent?.id) {
        recent.push(agent);
      }
    }

    return recent;
  }, [allAgents, getSortedAgentIds, activeCwd]);

  const commands: CommandItemData[] = useMemo(() => {
    if (!commandsData) return [];
    return commandsData.map((cmd) => ({
      name: cmd.name,
      description: cmd.description,
    }));
  }, [commandsData]);

  return {
    recentAgents,
    allAgents,
    features: FEATURES,
    commands,
    quickActions: QUICK_ACTIONS,
    isLoading: agentsLoading,
  };
}
```

