const handleAgentClick = (agent: AgentPath, e: React.MouseEvent) => {
  if (e.metaKey || e.ctrlKey) {
    window.open(window.location.pathname + '?dir=' + encodeURIComponent(agent.projectPath));
  } else {
    handleAgentSelect(agent);
  }
};
